import time
from enum import Enum

class CircuitState(Enum):
    CLOSED   = "closed"    # normal operation
    OPEN     = "open"      # blocking all calls
    HALF_OPEN = "half_open" # testing recovery

class CircuitBreaker:
    def __init__(self, failure_threshold: int = 3,
                 recovery_timeout: float = 60.0):
        self.failure_threshold = failure_threshold
        self.recovery_timeout  = recovery_timeout
        self._state            = CircuitState.CLOSED
        self._failure_count    = 0
        self._last_failure_ts  = 0.0

    @property
    def state(self) -> CircuitState:
        if (self._state == CircuitState.OPEN and
                time.time() - self._last_failure_ts > self.recovery_timeout):
            self._state = CircuitState.HALF_OPEN
        return self._state

    def call(self, fn, *args, **kwargs):
        if self.state == CircuitState.OPEN:
            raise RuntimeError(
                "Circuit breaker OPEN — downstream tool unavailable. "
                f"Retry after {self.recovery_timeout}s."
            )

        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            raise

    def _on_success(self):
        self._failure_count = 0
        self._state = CircuitState.CLOSED

    def _on_failure(self):
        self._failure_count += 1
        self._last_failure_ts = time.time()
        if self._failure_count >= self.failure_threshold:
            self._state = CircuitState.OPEN

# One breaker per external dependency
search_breaker = CircuitBreaker(failure_threshold=3, recovery_timeout=30.0)
db_breaker     = CircuitBreaker(failure_threshold=2, recovery_timeout=120.0)

