from dataclasses import dataclass
from typing import Any

@dataclass
class ToolOutput:
    success: bool
    data: Any | None
    error_code: str | None
    error_message: str | None

def parse_tool_output(raw: dict) -> ToolOutput:
    """
    Parse raw tool response into a typed object.
    Errors must be explicit — they cannot masquerade as data.
    """
    if "error" in raw:
        return ToolOutput(
            success=False,
            data=None,
            error_code=raw.get("error"),
            error_message=raw.get("message", "unknown error"),
        )
    return ToolOutput(
        success=True,
        data=raw.get("result", raw),
        error_code=None,
        error_message=None,
    )

def execute_and_inject(tool_name: str, arguments: dict,
                        executor, messages: list) -> None:
    raw = executor(tool_name, arguments)
    output = parse_tool_output(raw)

    if not output.success:
        # Inject the error explicitly — never silently continue
        messages.append({
            "role": "tool",
            "tool_call_id": "...",
            "content": f"ERROR: {output.error_code} — {output.error_message}. Do not continue until this is resolved.",
        })
        return

    # Only inject data if the call succeeded
    messages.append({
        "role": "tool",
        "tool_call_id": "...",
        "content": str(output.data),
    })

import time

def robust_orchestrate(query: str, agent_a, agent_b,
                        fallback_b_result: dict | None = None) -> dict:
    """Orchestrate with explicit failure handling at each stage."""
    # Stage A: data fetch — halt on failure (no fallback possible)
    for attempt in range(3):
        try:
            result_a = agent_a(query)
            break
        except Exception as exc:
            if attempt == 2:
                raise RuntimeError(f"Stage A failed after 3 attempts: {exc}") from exc
            time.sleep(2 ** attempt)

    # Stage B: enrichment — use fallback if it fails
    try:
        result_b = agent_b(result_a)
    except Exception as exc:
        if fallback_b_result is None:
            raise RuntimeError(f"Stage B failed and no fallback configured: {exc}") from exc
        # Log the failure but continue with the fallback
        print(f"WARNING: Stage B failed ({exc}). Using fallback result.")
        result_b = fallback_b_result

    return result_b

import time
from dataclasses import dataclass

@dataclass
class TimestampedResult:
    data: list
    fetched_at: float

def fetch_all_pages(api_fn, query: str, max_pages: int = 10) -> TimestampedResult:
    """Consume all pages before returning — prevents partial-page cascades."""
    all_items = []
    page = 1
    while page <= max_pages:
        response = api_fn(query=query, page=page)
        all_items.extend(response.get("items", []))
        if not response.get("has_next_page"):
            break
        page += 1
    else:
        raise RuntimeError(f"Pagination exceeded max_pages={max_pages}. Possible infinite loop.")

    return TimestampedResult(data=all_items, fetched_at=time.time())

def validate_freshness(result: TimestampedResult, max_age_seconds: float = 60.0) -> None:
    age = time.time() - result.fetched_at
    if age > max_age_seconds:
        raise ValueError(
            f"Tool result is stale: {age:.0f}s old (max allowed: {max_age_seconds}s). "
            "Re-fetch before proceeding."
        )
